class Solution {
    public long mostPoints(int[][] questions) {
        int n = questions.length;
        if (n == 0) return 0;
        long[] dp = new long[n + 1];
        for (int i = n - 1; i >= 0; i--) {
            int points = questions[i][0];
            int b = questions[i][1];
            int next = i + b + 1;
            long solve = points;
            if (next < n) {
                solve += dp[next];
            }
            long skip = dp[i + 1];
            dp[i] = Math.max(solve, skip);
        }
        return dp[0];
    }
}

